SourceCode.Declaration:
/// <summary>
/// Extension of the datasource <c>InventJournalTable</c> in the <c>InventJournalTransfer</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(InventJournalTransfer, InventJournalTable))]
final class InventJournalTransfer_InventJournalTable_ETGSPAIN_FormDataSource_Extension
{
}

Method.Source:
    /// <summary>
    /// Extension of the <c>active</c> method to customize behavior for Spanish companies.
    /// </summary>
    /// <returns>
    /// Returns an integer indicating the result of the operation.
    /// </returns>
    /// <remarks>
    /// This method disables the import button if the journal is posted and manages delete permissions based on the status of the packing slip import.
    /// </remarks>
	public int active()
	{
		int ret;
		ret = next active();

        if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
        {
            InventJournalTable      inventJournalTable						= this.cursor();
            FormControl             ETGSPAINInventJournalLineImportButton   = this.formRun().design().controlName('ETGSPAINInventJournalLineImport');

            // Deshabilitamos el botón si el diario está registrado
            ETGSPAINInventJournalLineImportButton.enabled(!inventJournalTable.Posted);


            ETGSPAINSalesPackingSlipImport etgSPAINSalesPackingSlipImport;

            select firstonly etgSPAINSalesPackingSlipImport
            where etgSPAINSalesPackingSlipImport.InventJournalId == inventJournalTable.JournalId
            && etgSPAINSalesPackingSlipImport.Status == IFRUniversalInterfaceSystemStatus::Posted;

            if (etgSPAINSalesPackingSlipImport)
            {
                this.allowDelete(false);
            }
            else
            {
                this.allowDelete(this.allowDelete());
            }
        }

		return ret;
	}
